  | { kind: 'summary'; id: number; name: string }
  | { kind: 'detail'; id: number; name: string; imageUrl: string; types: string[] };

export function cardTitle(view: PokemonCardView): string {
  if (view.kind === 'detail') {
    return `${view.name} (${view.types.length} types)`;
  }
  return view.name;
}

